sql:
SELECT COUNT(*) 
FROM amphibians 
WHERE species_id > 5;

SELECT species_id, COUNT(DISTINCT synonymies) AS num_unique_synonyms
FROM taxonomy_notes
GROUP BY species_id;

SELECT species_id 
FROM amphibians
WHERE LENGTH(common_name) > (SELECT AVG(LENGTH(common_name)) FROM amphibians);

external_knowledge:
- 'Tranquil waters of least concern' metaphorically refers to the IUCN conservation status 'Least Concern (LC)';
- 'No waves of change in their population' refers to a stable population trend;
- 'Emerging without an alternate name' refers to having no synonyms;
- 'Wear the names "Sphaenorhynchus seabrai" and "Sphoenohyla seabrai" as their second skin' is a metaphor for having those names listed as synonyms.

- 'Floating in the vast sea of uncertainty' is a metaphor for species with no IUCN conservation status; 
- 'Aliases' refers to synonyms and ITIS names;
- 'Taxonomic journeys' represent the taxon history of the species;
- 'Physical traits' correspond to the morphology description;
- 'Behavioral patterns' refer to the behavior description.

sql:
SELECT genus, AVG(LENGTH(common_name)) AS average_length_of_common_name
FROM amphibians
GROUP BY genus;

external_knowledge:
; 'None' in IUCN status indicates the species is not evaluated or has no data available;
'None' in ITIS names suggests the species may lack formal taxonomic recognition or is not yet classified in official records;
The familiar names of amphibians refer to their common names, which are more recognizable to the general public than scientific names;

sql:
SELECT synonymies, itis_names, taxon_history
FROM taxonomy_notes
WHERE species_id = 1;
